UPLOAD_JS = '''// ── CSV Upload ────────────────────────────────────────────────────────────────
function openUploadOverlay\(\){
  document.getElementById\('upload-overlay'\).classList.add\('show'\);
  const box = document.getElementById\('upload-box'\);
